<div class="page-title-row"><div><span class="text-muted">Last 30 days</span><h1>API Analytics</h1></div><a class="btn btn-outline-primary" href="/portal/api">Manage API tokens</a></div>
<div class="row g-3 mb-4"><div class="col-md-3"><div class="stat-card"><span>Requests</span><strong><?=number_format((int)($summary['requests']??0))?></strong></div></div><div class="col-md-3"><div class="stat-card"><span>Errors</span><strong><?=number_format((int)($summary['errors']??0))?></strong></div></div><div class="col-md-3"><div class="stat-card"><span>Average duration</span><strong><?=e($summary['avg_ms']??0)?> ms</strong></div></div><div class="col-md-3"><div class="stat-card"><span>Maximum duration</span><strong><?=e($summary['max_ms']??0)?> ms</strong></div></div></div>
