<div class="portal-card mt-4"><div class="card-header-row"><div><h2>Daily usage</h2><p>Simple operational view without requiring another charting library to colonize the portal.</p></div></div><div class="table-responsive"><table class="table mb-0"><thead><tr><th>Date</th><th>Requests</th><th>Errors</th><th>Average duration</th></tr></thead><tbody><?php foreach($daily as $d):?><tr><td><?=e($d['day'])?></td><td><?=number_format((int)$d['requests'])?></td><td><?=number_format((int)$d['errors'])?></td><td><?=e($d['avg_ms'])?> ms</td></tr><?php endforeach?></tbody></table></div></div>
